/*
    SQL ID : editConvertClass
    설  명 : 성적기초정보관리 > 성적환산등급 수정
*/
UPDATE TB_LMS_MRK_CNVS_GRD
   SET AVG_CRDTS = #{avgScor}
       , CRTR_SCR = #{baseScor}
       , START_SCR = #{startScor}
       , END_SCR = #{endScor}
       , MDFR_ID = #{mdfrId}
       , MOD_DTTM = FN_DTTM()
 WHERE ORG_ID = #{orgId}
   AND UNIV_CD = #{uniCd}
   AND MRK_GRDCD = #{scorCd}

        /*
            SQL ID : editConvertUseYn
            설  명 : 성적기초정보관리 > 성적환산등급 사용여부 수정
        */	
		UPDATE TB_LMS_MRK_CNVS_GRD
		      SET USEYN = #{useYn}
		             , MDFR_ID = #{mdfrId}
		             , MOD_DTTM = FN_DTTM()
		 WHERE MRK_GRDCD = #{scorCd}
		 	AND ORG_ID = #{orgId}
		 	AND UNIV_CD = #{uniCd}

/*
    SQL ID : editRelativeClass
    설  명 : 성적기초정보관리 > 상대평가비율 수정
*/
UPDATE MRK_RLTV_EVL_CRTRRT
   SET SMRK_GRDCD = #{startScorCd}
       , END_SCR_CD = #{endScorCd}
       , SPRCNTL = #{startRatio}
       , END_PRCNTL = #{endRatio}
       , MDFR_ID = #{mdfrId}
       , MOD_DTTM = FN_DTTM()
 WHERE ORG_ID = #{orgId}
   AND EVL_CRTR_CD = #{scorRelCd}
   AND UNIV_CD = #{uniCd}

        /*
            SQL ID : editRelativeUseYn
            설  명 : 성적기초정보관리 > 상대평가비율 사용여부 수정
        */	
		UPDATE MRK_RLTV_EVL_CRTRRT
		      SET USEYN = #{useYn}
		             , MDFR_ID = #{mdfrId}
		             , MOD_DTTM = FN_DTTM()
		 WHERE EVL_CRTR_CD = #{scorRelCd}
