mapper.select:
/* SQL ID : selectLateScoreClass 설 명 : 출석점수기준 강의 지각감전기준 정보 조회 */ SELECT LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_1' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM1, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_2' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM2, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_3' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM3, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_4' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM4, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_5' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM5, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_6' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM6, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_7' THEN SUBSTR(MRK_STNG_CDNM, 8) END, ',') WITHIN GROUP (ORDER BY MRK_STNG_CDNM) AS LATE_SCORE_NM7,
LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_1' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL1, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_2' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL2, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_3' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL3, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_4' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL4, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_5' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL5, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_6' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL6, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_7' THEN MRK_STNG_VL END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_VAL7,
LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_1' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD1, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_2' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD2, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_3' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD3, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_4' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD4, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_5' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD5, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_6' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD6, LISTAGG(CASE WHEN MRK_STNG_CD = 'LATE_SCORE_7' THEN MRK_STNG_CD END, ',') WITHIN GROUP (ORDER BY MRK_STNG_VL) AS LATE_SCORE_CD7 FROM TB_LMS_SCORE_ATND_CONF WHERE ORG_ID = 'ORG0000001' AND MRK_STNG_GBNCD = 'LESSON' AND MRK_STNG_CD IN ('LATE_SCORE_1', 'LATE_SCORE_2', 'LATE_SCORE_3', 'LATE_SCORE_4', 'LATE_SCORE_5', 'LATE_SCORE_6', 'LATE_SCORE_7') ORDER BY MRK_STNG_CD

